<script>
function ptrError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_traceability_process_failed', 'Production Traceability failed to process.');?>);$('.error_data_delete').fadeIn();}
function ptrFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant_id:$('#filter_plant_id').val(),stock_type:$('#filter_stock_type').val(),trace_source:$('#filter_trace_source').val(),material_code:$('#filter_material').val(),keyword:$('#filter_keyword').val()};}
function ptrQuery(){return $.param(ptrFilters());}
$(function(){if($.fn.datepicker){$('.ptr-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant_id,#filter_stock_type,#filter_trace_source').select2({width:'100%',allowClear:true});$('#filter_material').select2({width:'100%',allowClear:true,placeholder:'Cari output/source/raw material...',minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/production_traceability/production_traceability_action.php?act=material_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
var dt=$('#dtb_production_traceability').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[6],className:'text-right'},{width:'38px',targets:0},{width:'58px',targets:1}],ajax:{url:'<?=base_admin();?>modul/production_traceability/production_traceability_data.php',type:'post',data:function(d){$.extend(d,ptrFilters());},error:function(xhr){console.log(xhr.responseText);ptrError(<?=prod_js('production_traceability_load_failed', 'Traceability data failed to load.');?>);}}});
$('#btn_filter_ptr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ptr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant_id,#filter_stock_type,#filter_trace_source').val('').trigger('change');$('#filter_material').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_ptr,#btn_excel_ptr_top').click(function(){window.location='<?=base_admin();?>modul/production_traceability/production_traceability_action.php?act=excel&'+ptrQuery();});
$(document).on('click','.btn-ptr-detail',function(){var el=$(this);$.post('<?=base_admin();?>modul/production_traceability/production_traceability_action.php?act=detail',{gr_id:el.data('id'),output_stock_layer_id:el.data('output-layer')},function(html){$('#ptr_detail_body').html(html);$('#modal_detail_ptr').modal('show');}).fail(function(){ptrError('Detail genealogy gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
